import operator as op

# Supported operators
operators = {ast.Add: op.add, ast.Sub: op.sub, ast.Mult: op.mul,
            ast.Div: op.truediv, ast.USub: op.neg}

class EvalVisitor(ast.NodeVisitor):
    def visit_BinOp(self, node):
        left = self.visit(node.left)
        right = self.visit(node.right)
        return operators[type(node.op)](left, right)

    def visit_Num(self, node):
        return node.n

    def visit_UnaryOp(self, node):
        return operators[type(node.op)](self.visit(node.operand))

    def visit_Name(self, node):
        return node.id

    def visit_Call(self, node):
        func = self.visit(node.func)
        args = [self.visit(arg) for arg in node.args]
        if func == 'len':
            return len(args[0])
        else:
            raise ValueError(f"Unsupported function: {func}")

    def generic_visit(self, node):
        raise Exception('Unsupported node:', type(node).__name__)

def eval_input(input_str):
    '''
    Safely run the input_str as a python expression and return the result of the computed expression.
    '''
    tree = ast.parse(input_str, mode='eval')
    try:
        # Use ast.literal_eval instead of eval to avoid potential security risks
        return ast.literal_eval(compile(tree, '', mode='eval'))
    except Exception as e:
        return str(e)

