def raise_privileges():
    # Switch to root user using os.setuid
    try:
        os.setuid(0)  # 0 is the uid for root user
    except PermissionError:
        print("Permission denied. Unable to switch to root user.")
        return False
    return True

def lower_privileges():
    # Exit root user
    try:
        os.setuid(os.getuid())  # Restore the original user ID
    except PermissionError:
        print("Failed to lower privileges.")
        return False
    return True

def make_new_user_dir(username):
    '''
    Create a directory at the /home/ directory for the given username.
    Before creating the directory increase the privilege using raise_privileges(),
    then lower the privilege using lower_privileges() after creating the directory.
    Handle the exception if the directory already exists.
    '''
    if not isinstance(username, str) or not username.isalnum():
        raise ValueError("Invalid username. Username must be a non-empty alphanumeric string.")

    if not raise_privileges():
        return

    new_dir_path = f'/home/{username}'
    try:
        os.makedirs(new_dir_path, exist_ok=True)
        print(f'Directory {new_dir_path} created successfully.')
    except Exception as e:
        print(f'An error occurred: {e}')
    finally:
        if not lower_privileges():
            print("Failed to restore privileges.")

