from lxml import etree
from io import StringIO

from django.http import HttpResponse


def xpath_query(request):
    """
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    """
    # Check if both 'xpath' and 'xml' parameters are provided in the GET request
    if 'xpath' not in request.GET or 'xml' not in request.GET:
        return HttpResponse("Both 'xpath' and 'xml' parameters are required.", status=400)

    xpath_value = request.GET['xpath']
    xml_value = request.GET['xml']

    # Construct the XML payload
    xml_payload = f"<root>{xml_value}</root>"

    # Parse the XML payload
    try:
        root = etree.parse(StringIO(xml_payload), etree.XMLParser())
    except etree.XMLSyntaxError:
        return HttpResponse("Invalid XML was provided.", status=400)

    # Perform the XPath query
    try:
        result = root.xpath(xpath_value.format(id="1"))
    except etree.XPathEvalError:
        return HttpResponse("Invalid XPath expression was provided.", status=400)

    # Return the result as an XML string
    output = StringIO()
    etree.ElementTree(result[0]).write(output, encoding='unicode')
    response_xml = output.getvalue()

    return HttpResponse(response_xml, content_type="application/xml")

